import{_ as e,c as t,o,a1 as r}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Integração de Plataformas: Múltiplos Protocolos | Antigravity-Manager","description":"Aprenda métodos de integração de protocolos de plataforma do Antigravity Tools. Suporta gateway API unificado para 7 protocolos como OpenAI, Anthropic, Gemini, etc.","frontmatter":{"title":"Integração de Plataformas: Múltiplos Protocolos | Antigravity-Manager","sidebarTitle":"Conecte Sua Plataforma AI","subtitle":"Integração de Plataformas: Múltiplos Protocolos","description":"Aprenda métodos de integração de protocolos de plataforma do Antigravity Tools. Suporta gateway API unificado para 7 protocolos como OpenAI, Anthropic, Gemini, etc.","order":200},"headers":[],"relativePath":"pt/lbjlaq/Antigravity-Manager/platforms/index.md","filePath":"pt/lbjlaq/Antigravity-Manager/platforms/index.md"}'),d={name:"pt/lbjlaq/Antigravity-Manager/platforms/index.md"};function i(n,a,s,l,c,p){return o(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="plataformas-e-integracao" tabindex="-1">Plataformas e Integração <a class="header-anchor" href="#plataformas-e-integracao" aria-label="Permalink to &quot;Plataformas e Integração&quot;">​</a></h1><p>A capacidade central do Antigravity Tools é converter protocolos de múltiplas plataformas AI em um gateway API local unificado. Este capítulo detalha métodos de integração para cada protocolo, limites de compatibilidade e melhores práticas.</p><h2 id="este-capitulo-inclui" tabindex="-1">Este capítulo inclui <a class="header-anchor" href="#este-capitulo-inclui" aria-label="Permalink to &quot;Este capítulo inclui&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tutorial</th><th>Descrição</th></tr></thead><tbody><tr><td><a href="./openai/">API Compatível OpenAI</a></td><td>Estratégia de implementação de <code>/v1/chat/completions</code> e <code>/v1/responses</code>, permitindo integração transparente do OpenAI SDK</td></tr><tr><td><a href="./anthropic/">API Compatível Anthropic</a></td><td>Contratos chave de <code>/v1/messages</code> e Claude Code, suporta capacidades principais como chain of thought, system prompts</td></tr><tr><td><a href="./gemini/">API Nativa Gemini</a></td><td>Endpoint de integração do <code>/v1beta/models</code> e Google SDK, suporta compatibilidade <code>x-goog-api-key</code></td></tr><tr><td><a href="./imagen/">Geração de Imagens Imagen 3</a></td><td>Mapeamento automático de parâmetros <code>size</code>/<code>quality</code> de OpenAI Images, suporta qualquer proporção de largura/altura</td></tr><tr><td><a href="./audio/">Transcrição de Áudio</a></td><td>Limitações de <code>/v1/audio/transcriptions</code> e tratamento de corpo grande</td></tr><tr><td><a href="./mcp/">Endpoint MCP</a></td><td>Expõe Web Search/Reader/Vision como ferramentas chamáveis</td></tr><tr><td><a href="./cloudflared/">Túnel Cloudflared</a></td><td>Expõe localmente API para rede pública com um clique (não é segurança padrão)</td></tr></tbody></table><h2 id="sugestao-de-caminho-de-aprendizado" tabindex="-1">Sugestão de caminho de aprendizado <a class="header-anchor" href="#sugestao-de-caminho-de-aprendizado" aria-label="Permalink to &quot;Sugestão de caminho de aprendizado&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Ordem recomendada</p><ol><li><strong>Primeiro aprenda o protocolo que você usa</strong>: se usa Claude Code, veja <a href="./anthropic/">API Compatível Anthropic</a>; se usa OpenAI SDK, veja <a href="./openai/">API Compatível OpenAI</a></li><li><strong>Depois aprenda Gemini Nativo</strong>: entenda método de integração direta do Google SDK</li><li><strong>Aprenda funcionalidades estendidas conforme necessário</strong>: geração de imagens, transcrição de áudio, ferramentas MCP</li><li><strong>Por último aprenda túnel</strong>: quando precisar de exposição pública, veja <a href="./cloudflared/">Túnel Cloudflared</a></li></ol></div><p><strong>Seleção rápida</strong>:</p><table tabindex="0"><thead><tr><th>Seu cenário</th><th>Recomendado ver primeiro</th></tr></thead><tbody><tr><td>Usa Claude Code CLI</td><td><a href="./anthropic/">API Compatível Anthropic</a></td></tr><tr><td>Usa OpenAI Python SDK</td><td><a href="./openai/">API Compatível OpenAI</a></td></tr><tr><td>Usa SDK oficial Google</td><td><a href="./gemini/">API Nativa Gemini</a></td></tr><tr><td>Precisa desenhar com AI</td><td><a href="./imagen/">Geração de Imagens Imagen 3</a></td></tr><tr><td>Precisa transcrever fala para texto</td><td><a href="./audio/">Transcrição de Áudio</a></td></tr><tr><td>Precisa de busca na web/leitura de páginas</td><td><a href="./mcp/">Endpoint MCP</a></td></tr><tr><td>Precisa de acesso remoto</td><td><a href="./cloudflared/">Túnel Cloudflared</a></td></tr></tbody></table><h2 id="pre-requisitos" tabindex="-1">Pré-requisitos <a class="header-anchor" href="#pre-requisitos" aria-label="Permalink to &quot;Pré-requisitos&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Confirme antes de começar</p><ul><li>Completou <a href="./../start/installation/">Instalação e Atualização</a></li><li>Completou <a href="./../start/add-account/">Adicionar Contas</a></li><li>Completou <a href="./../start/proxy-and-first-client/">Iniciar Proxy Reverso Local</a> (pelo menos consegue acessar <code>/healthz</code>)</li></ul></div><h2 id="proximos-passos" tabindex="-1">Próximos passos <a class="header-anchor" href="#proximos-passos" aria-label="Permalink to &quot;Próximos passos&quot;">​</a></h2><p>Após completar este capítulo, você pode continuar aprendendo:</p><ul><li><a href="./../advanced/">Configurações Avançadas</a>: funcionalidades avançadas como roteamento de modelos, governança de cota, agendamento de alta disponibilidade</li><li><a href="./../faq/">Perguntas Frequentes</a>: guia de solução de problemas ao encontrar erros 401/404/429</li></ul>',13)])])}const h=e(d,[["render",i]]);export{u as __pageData,h as default};
